var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐야? 테스트 시간이 끝나기도 전에 전부 처치라고…? 그런 게 가능한 거였어?!","JPN":"え？　制限時間を大幅に残して倒すなんて……？　そんなのできるの！？","ENG":"What? She just defeated all of them before the timer ended... How is that even possible?!","TWN":"什麼鬼？考試時間都還沒結束就都消滅完啦…？這是有可能的嗎？！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"와아! 완전 빠르고 정확했어! 이건 틀림없이 최소 A급 확정이야!","JPN":"わあ！　すごく早くて正確だった！　絶対A級以上だよ！","ENG":"Wow! You were so fast and accurate! I'm sure you also got a Grade A, at least!","TWN":"哇！快狠準欸！這絕對至少有A級吧！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"시엘 마로니에 – 관리국 공인 카운터 등급 C","JPN":"シエル・マロニエ – 管理局公認カウンターランクC","ENG":"Ciel Marronier – Official Administration Counter Grade: C.","TWN":"希爾·麥洛尼爾 – 管理局認證制裁者等級C"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L9_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"응…?","JPN":"え……？","ENG":"Mm...?","TWN":"什麼…？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"에에엥?!","JPN":"えええっ！？","ENG":"Whaaat?!","TWN":"怎麼會？！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"저기 잠깐만요. 이거 뭔가 잘못된 거 아녜요?","JPN":"ちょって待ってください。何か間違ってるんじゃないですか？","ENG":"Um, excuse me. I think there's something wrong with the results.","TWN":"等一下，是不是哪裡弄錯啦？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"분명 시엘은 시뮬레이터의 침식체들을 전부 처리했잖아요! 한 대도 안 맞고요!","JPN":"シエルちゃんはシミュレーターの侵食体を全部倒したんですよ？　たったの一度も被撃せずに！","ENG":"Ciel defeated all the C.O.s in the simulation! She wasn't even hit once!","TWN":"希爾不是把模擬器的侵蝕體都消滅了嗎！而且她完全沒有被打到欸！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TEST_NPC_ACADEMY_NULL","text":{"KOREA":"죄송하지만 저희는 평가 기준에 따라 시험을 진행할 뿐입니다. 기준에는 문제가 없었어요.","JPN":"申し訳ありません。ですが私たちは評価基準に従い試験を行っています。そして基準に問題はありませんでした。","ENG":"I'm sorry, but we have our own criteria for this assessment. There was no mistake made in the process.","TWN":"很抱歉，我們是根據鑑定標準進行考試的，標準沒有問題。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TEST_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"에… 말도 안 돼…","JPN":"え……なんで……","ENG":"That's... impossible...","TWN":"喔…奇怪…"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"본인의 CRF란 것이 관리국이 바라는 기준에는 그리 대단치 못한 모양이구려.","JPN":"自分のCRFが管理局の求めるレベルに遠く及ばなかったようですね。","ENG":"It appears that my CRF is not up to the standards of the Administration.","TWN":"可能以管理局的標準來看，在下的CRF不算厲害。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"안 됐지만 어쩔 수 없네. 카운터에 대해 누구보다 잘 아는 기관에서 C급이라는데, 우리가 뭘 어쩌겠어?","JPN":"残念だけど、仕方ないわね。カウンターについて誰よりも知り尽くしている管理局がC級判定を出したんだから、私たちじゃ反論のしようもないわ。","ENG":"I guess there's nothing we can really do about it. After all, they know more about Counters than any of us, so if they say you're a Grade C, you must be one, right?","TWN":"那也只能接受囉？畢竟在制裁者界最具公信力的機關說你是C級，那我們還能說什麼？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"일리가 있는 말이오. 규칙이 통하는 곳에서는 그 규칙을 따르는 것이 정도이니까.","JPN":"その通りです。ルールのあるところでは、そのルールに従うのが常ですから。","ENG":"Your logic makes sense. When one is in Rome, one must do as the Romans do.","TWN":"說的有道理，既然已經定好規則，那就該遵守規則。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"정말이야? 엘리트인 나이엘이 해내지 못한 걸 신입생이 해내다니…","JPN":"まじか？　エリートのナイエルにできなかったことを、新入生がやってのけるとは……","ENG":"Really? But even the elite Naielle wasn't able to do what the new kid did...","TWN":"真的假的？新生做到的事是連奈爾也做不到的欸…"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"그러고 보면 지난 모의전투훈련 때도, 결국 신입생이 졌지만 나이엘이 꽤나 고전했어.","JPN":"そういえばこの間の模擬訓練で、新入生が負けはしたけど、ナイエルも結構苦戦していたな。","ENG":"Come to think of it, although Naielle defeated the new kid in the simulation training, she did struggle during the match.","TWN":"現在回想起來，上次的模擬戰訓練新生雖然輸給奈爾，但奈爾打得很辛苦。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"심지어 나이엘은 A급 카운터로 인정 받았잖아.","JPN":"それに、ナイエルはA級カウンターって判定が出たんだろ？","ENG":"What's more is that Naielle's been recognized as a Grade A Counter.","TWN":"而且奈爾還獲得A級制裁者的認證欸！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"A급이 해내지 못한 걸 C급이 해낼 수 있다면… 우리도 할 수 있는 걸까?","JPN":"A級にできないことをC級がやってのけたってことは……俺たちにもまだ希望があるんじゃね？","ENG":"If a Grade C can do what a Grade A couldn't... then maybe we can do it too.","TWN":"要是 C級可以做到A級做不到的事…那我們也可以嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"하하, 다들 정말 순진하구나?","JPN":"はは、お前たち、本当にピュアなんだな。","ENG":"Haha, aren't you a couple of naive fellows?","TWN":"哈哈，你們還真是頭腦簡單呢。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"음? 그게 무슨 소리야?","JPN":"はあ？　どういうことだ？","ENG":"Huh? What's that supposed to mean?","TWN":"嗯？什麼意思？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"시뮬레이션이나 시합 같은 건 그저 짜여진 규칙 위에서 놀아나는 게임일 뿐이야.","JPN":"シミュレーションとか、試合とかは決められたルールの中でじゃれ合うゲームに過ぎない。","ENG":"Simulations and matches are merely games with rules.","TWN":"模擬器或測驗，都是在定好的規則下進行的扮家家酒而已。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"실전에서의 우위를 판가름하는 진짜 척도는 순수한 강함이지.","JPN":"実戦では純粋な強さのみが勝敗を分けるんだ。","ENG":"It's not a true indicator of one's power in the real world.","TWN":"實戰中只講求實力，實力強才能取得優勢。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"그래서 심사원들도 시뮬레이터는 측량도구 정도로만 취급할 뿐, 등급은 철저히 CRF를 기준으로만 매기고 있는 거 아니겠어?","JPN":"だから審査委員たちもシミュレーターはいち指標として見ているだけで、ランクはあくまでCRFのみで判断しているだろう。","ENG":"Even for the examiners, the simulator only serves as a tool. The grade is assessed based on CRF, isn't it?","TWN":"所以評審只把模擬器視為是測量工具，等級鑑定還是以CRF為準不是嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"끄응… 그 말도 틀린 얘긴 아니네.","JPN":"ううん……確かにそれもそうだな。","ENG":"Ugh... You're not wrong about that...","TWN":"嗯嗯…你說的沒錯。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"그, 그래도 가능성은 있는 거잖아? 우리도 노력만 하면…!","JPN":"で、でも可能性はあるんじゃないか？　俺たちだって努力すりゃ……！","ENG":"B-but still, there is a possibility, no? If we just put in the effort...!","TWN":"但，還是有可能的吧？只要我們夠努力…！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"너희도 아카데미를 다니는 내내 남들만큼 노력했을 거야.","JPN":"お前たちもアカデミーでの毎日の中で、できるだけの努力はしてきたはずだ。","ENG":"I'm sure you tried your best at the Academy. Even more than others, perhaps.","TWN":"我相信你們在學院裡跟其他人一樣努力。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"그런데 뭐가 바뀌었지? 너희는 여전히 하위권의 D급에 머물고 있을 뿐이잖아?","JPN":"でも、それで何か変わったか？　お前たちは相変わらず底辺のD級から脱せずにいるだろう？","ENG":"But what has changed? Aren't you still at the bottom?","TWN":"但有改變什麼嗎？你們還是停留在底層的D級不是嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"그래서… 우리더러 어쩌라는 거야? 우린 해볼 수 있는 시도는 다 해봤다고.","JPN":"だから……だからってどうしろってんだよ！　俺たちだってできることは全てやったんだ。","ENG":"So... what do you want us to do? We tried everything there is.","TWN":"那…你到底是想要我們怎麼樣？能嘗試的我們都已經嘗試了！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"내가 가지고 있어.","JPN":"だから、これはどうだ？","ENG":"I have it.","TWN":"我有你們要的東西。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"뭐…?","JPN":"何だと……？","ENG":"What...?","TWN":"什麼…？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"너희가 그토록 찾던 엘릭서. 내가 줄 수 있다고.","JPN":"お前たちが探し求めていたエリクサー。あげてもいいぜ。","ENG":"I have the Elixir you've been looking for. I can give that to you.","TWN":"你們不是想要聖水嗎？我可以給你們。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"그게 정말이야?!","JPN":"本当か！？","ENG":"Are you serious?!","TWN":"是真的嗎？！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L45_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"그럼- 내 작은 부탁 하나만 들어주면, 너희에게 이걸 줄게.","JPN":"もちろんだ。僕の小さなお願いを一つだけ聞いてくれたら、お前にこれをくれてやる。","ENG":"Well, if... you do me this tiny favor, I'll give it to you.","TWN":"那當然，只要你們替我完成一件小事，我就給你們。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"이것만 있으면 너희도 나이엘 같은… 아니, 엘릭서와의 상성만 좋다면 <color=#ff3636>그보다 더 뛰어난 잠재력</color>을 발현할 지도 몰라.","JPN":"これさえあればお前たちもナイエルのような……いや、エリクサーとの相性がよければ<color=#ff3636>それよりさらに高い潜在力</color>が発現するかもしれない。","ENG":"With this, you can be like Naielle... No, if you're compatible with the Elixir, you might even <color=#ff3636>have the potential to surpass her</color>.","TWN":"只要有這個，你們也可以像奈爾一樣…不，要是和聖水相容的話，或許可以發揮<color=#ff3636>比她更厲害的潛力</color>呢。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"그게… 진짜 엘릭서라고?","JPN":"それは……本当にエリクサーなのか？","ENG":"That's... really the Elixir?","TWN":"那是…真的聖水？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"네 말을 어떻게 믿어?","JPN":"お前をどう信じればいいんだ？","ENG":"But how can I trust you?","TWN":"我憑什麼相信你？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"아카데미 학생 같긴 한데, 우린 네가 누군지도 몰라.","JPN":"アカデミーの生徒っぽいけど、俺たちからすればお前は赤の他人だぞ。","ENG":"You look like a student at the Academy, but we don't know who you really are.","TWN":"你看起來雖然像是學院的學生，但我們根本不認識你。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"존재감 없이 지내는 학생A. 그 정도로만 알아 둬.","JPN":"影の薄い生徒A。そのぐらいに思っておいてくれ。","ENG":"Let's just say I'm a quiet student who doesn't like to stand out.","TWN":"你們就當我是邊緣人A同學吧。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"그리고 난 너희에게 시비를 거는 게 아니라 도움을 주려는 거야.","JPN":"そして、別に僕は、お前たちに喧嘩を売ろうとしているわけじゃない。助けようとしているんだ。","ENG":"Plus, I'm not here to fight you. I'm here to help you.","TWN":"況且我不是來找碴的，我是來幫你們的。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"도움이라고…?","JPN":"助ける、だと……？","ENG":"Help us...?","TWN":"來幫我們…？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"나도… 너희처럼 노력만으로 차이를 극복할 수 있다고 생각하던 때가 있었거든.","JPN":"僕も……お前たちのように努力だけで差を埋められると思っていた時期があったんだ。","ENG":"There was a time... when I also thought effort could overcome anything. Just like you.","TWN":"因為…我曾經也像你們一樣，以為勤能補拙，只要努力就能夠克服差異。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"방금 무슨 소리지?","JPN":"今の音は何？","ENG":"What was that sound?","TWN":"剛才那是什麼聲音？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐, 뭐야? 깜짝이야. 건물이라도 무너지는 줄 알았네.","JPN":"な、何？　びっくりした。建物が崩れる音がしたわ。","ENG":"Yikes. What was it? I thought it was a building collapsing.","TWN":"搞，搞什麼？嚇我一跳，我還以為是建築物倒塌咧！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"어라?","JPN":"あれ？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"저기 전광판 좀 봐! 새 기록이 올라왔어!","JPN":"あの電光板を見て！　新記録が出てる！","ENG":"Look at the scoreboard over there! There's a new record!","TWN":"你看螢幕！又有新的紀錄咧！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"narration","speaker":null,"text":{"KOREA":"등록되지 않은 참가자 – 관리국 공인 카운터 등급 A","JPN":"未登録の参加者 – 管理局公認カウンターランクA","ENG":"Unregistered Participant – Official Administration Counter Grade: A.","TWN":"未登記的參加者 – 管理局認證制裁者等級A"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"저게 어떻게 된 거야? 아카데미에 나이엘 말고도 A급 카운터가 또 있었다고?","JPN":"いったいどうなってるの？　アカデミーにナイエル以外にもA級カウンターがいたってこと？","ENG":"How's that possible? There's another Grade A Counter besides Naielle at the Academy?","TWN":"怎麼回事？學院裡除奈爾之外還有其他A級制裁者喔？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 학생회장은 오늘 여기에 오지 않았잖아?","JPN":"でも生徒会長は今日来てないんでしょ？","ENG":"But the Student President isn't here today, is she?","TWN":"可是學生會長今天又沒有來？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"그런데 이름이 왜 안 나오는 거지? 그냥 오류인 거 아냐?","JPN":"というか名前が非表示なのはどうして？　ただのエラーじゃない？","ENG":"And why's there no name? Is it just an error?","TWN":"上面怎麼沒有寫名字？還是只是螢幕故障？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};